patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 73218f377a06..6e9e29c2482b 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -14589,6 +14589,15 @@ ResTy BoUpSLP::processBuildVector(const TreeEntry *E, Type *ScalarTy,
     for (unsigned I : seq<unsigned>(GatheredScalars.size()))
       if (E->Scalars[I] == GatheredScalars[ReorderMask[I]])
         SubVectorsMask[ReorderMask[I]] = PoisonMaskElem;
+    // Ensure SubVectorsMask has the correct size to match the vector factor.
+    // The vector factor VF determines the final vector width that will be used
+    // in shuffle operations, and CommonMask in finalize() will have this size.
+    // Resize SubVectorsMask if necessary to prevent assertion failures.
+    unsigned VF = E->getVectorFactor();
+    if (SubVectorsMask.size() < VF)
+      SubVectorsMask.resize(VF, PoisonMaskElem);
+    else if (SubVectorsMask.size() > VF)
+      SubVectorsMask.resize(VF);
   } else {
     SubVectorsMask.clear();
   }

